        _men1_13 = Init1_13();
        _men1 = Init1();
        _men2 = Init2();
    }

    public string? ToCharString(int men, int ku, int ten)
    {
        switch (men)
        {
            case 0:
                return (ku == 0 && ten >= 0 && ten < _men0.Length) ? _men0[ten].ToString() : null;
            case 1:
                if (ku <= 0 || ku >= 95 || ten <= 0) return null;
                if (ku <= 13)
                {
                    var row = _men1_13[ku];
                    return row != null && ten < row.Length ? row[ten] : null;
                }
                else
                {
                    var row = _men1[ku];
                    return row != null && ten < row.Length ? CodeToCharString(row[ten]) : null;
                }
            case 2:
                if (ku <= 0 || ku >= 95 || ten <= 0) return null;
                var row2 = _men2[ku];
                return row2 != null && ten < row2.Length ? CodeToCharString(row2[ten]) : null;
        }
        return null;
    }

    private static string? CodeToCharString(int unicode)
    {
        if (unicode == 0) return null;
        return char.ConvertFromUtf32(unicode);
    }

